const __pageData = JSON.parse('{"title":"REST vs GraphQL vs gRPC vs tRPC 实战对比","description":"深度对比四种主流API设计风格，通过真实代码示例、性能基准和决策树帮助开发者选择合适的技术方案。","frontmatter":{"title":"REST vs GraphQL vs gRPC vs tRPC 实战对比","description":"深度对比四种主流API设计风格，通过真实代码示例、性能基准和决策树帮助开发者选择合适的技术方案。","date":"2026-05-02T00:00:00.000Z","tags":["API Design","REST","GraphQL","gRPC","tRPC","Backend","TypeScript"],"category":"examples"},"headers":[],"relativePath":"examples/api-design/rest-graphql-grpc-comparison.md","filePath":"examples/api-design/rest-graphql-grpc-comparison.md","lastUpdated":1777789647000}');
